    30→const MyOrdersDetails = ({ route }: ScreenProps<'MyOrdersDetails'>) => {
    31→  const navigation = useNavigation();
    32→  const hasFocused = useRef(false);
    33→  const modalizeRef = useRef<PropsModalizeRef>(null);
    34→  const modalizeRefInfo = useRef<PropsModalizeRef>(null);
    35→
    36→  const { orderDetail, orderDetailActions } = useRootStore(
    37→    useShallow(state => ({
    38→      orderDetail: state.orderDetail,
    39→      orderDetailActions: state.orderDetailActions,
    40→    })),
    41→  );
    42→
    43→  const transactionId = route.params?.transactionId;
    44→  const passedType = route.params?.type;
    45→  const passedIcon = route.params?.icon;
    46→  const passedStatus = route.params?.status;
    47→  const passedOrigination = route.params?.origination;
    48→
    49→  useFocusEffect(
    50→    useCallback(() => {
    51→      if (!hasFocused.current) {
    52→        eventScreenViewV3(
    53→          'detalhe_pedido',
    54→          'hub_recompensas_spmais',
    55→          'monetizacao',
    56→          {
    57→            location_1: 'monetizacao',
    58→            location_2: 'hub_recompensas_spmais',
    59→            location_3: 'detalhe_pedido',
    60→          },
    61→        );
    62→        hasFocused.current = true;
    63→      }
    64→
    65→      if (transactionId) {
    66→        orderDetailActions.reset();
    67→        getOrderDetail({ transactionId });
    68→      }
    69→
    70→      return () => {
    71→        hasFocused.current = false;
    72→        orderDetailActions.reset();
    73→      };
    74→    }, [
    75→      transactionId,
    76→      orderDetailActions,
    77→    ]),
    78→  );
    79→
    80→  const handleGoBack = () => {
    81→    navigation.goBack();
    82→  };
    83→
    84→  const handleOpenReportProblem = () => {
    85→    eventSelectContent({
    86→      content_type: 'cta',
    87→      content_id: 'relatar_problema',
    88→      location_1: 'monetizacao',
    89→      location_2: 'hub_recompensas_spmais',
    90→      location_3: 'detalhe_pedido',
    91→    });
    92→
    93→    eventModalView({
    94→      content_id: 'contato_telefones',
    95→      location_1: 'monetizacao',
    96→      location_2: 'hub_recompensas_spmais',
    97→      location_3: 'detalhe_pedido',
    98→    });
    99→
   100→    modalizeRef.current?.open?.();
   101→  };
   102→
   103→  const handleCloseReportProblem = () => {
   104→    modalizeRef.current?.close?.();
   105→  };
   106→
   107→  const handleOpenInfo = () => {
   108→    modalizeRefInfo.current?.open?.();
   109→  };
   110→
   111→  const handleCloseInfo = () => {
   112→    modalizeRefInfo.current?.close?.();
   113→  };
   114→
   115→  const isLoading = orderDetail.status === OrderDetailStatus.LOADING;
   116→  const hasError = orderDetail.status === OrderDetailStatus.ERROR;
   117→  const { height } = Dimensions.get('window');
   118→
   119→  const handleRetry = () => {
   120→    if (transactionId) {
   121→      getOrderDetail({ transactionId });
   122→    }
   123→  };
   124→
   125→  const transaction = orderDetail.orderDetail;
   126→
   127→  const isValidTransactionType = (
   128→    type: string | undefined,
   129→  ): type is TransactionType => {
   130→    return (
   131→      type === 'CREDIT' ||
   132→      type === 'RESCUE' ||
   133→      type === 'EXPIRED' ||
   134→      type === 'REFUNDED'
   135→    );
   136→  };
   137→
   138→  const enrichedTransaction = useMemo(() => {
   139→    if (!transaction) return undefined;
   140→    return {
   141→      ...transaction,
   142→      type: isValidTransactionType(passedType) ? passedType : transaction.type,
   143→      icon: passedIcon || transaction.icon,
   144→      status: passedStatus || transaction.status,
   145→      details: {
   146→        ...transaction.details,
   147→        provider: passedOrigination || transaction.details?.provider || '',
   148→      },
   149→    };
   150→  }, [
   151→    transaction,
   152→    passedType,
   153→    passedIcon,
   154→    passedStatus,
   155→    passedOrigination,
   156→  ]);
   157→
   158→  const isCashback = passedType === 'RESCUE';
   159→
   160→  const processedData = useMemo(() => {
   161→    if (!enrichedTransaction) {
   162→      return {
   163→        cardTitle: '',
   164→        formattedPointsValue: '',
   165→        highlightText: '',
   166→        formattedCurrencyValue: '',
   167→        marketplaceContent: undefined,
   168→        showOrderNumber: false,
   169→        showStatus: false,
   170→        showValue: false,
   171→      };
   172→    }
   173→
   174→    const gainType = getTransactionGainType(enrichedTransaction);
   175→    const formattedCurrencyValue = formatToCurrency(
   176→      enrichedTransaction.currencyValue,
   177→    );
   178→    const marketplaceValuePoints =
   179→      enrichedTransaction?.marketplace?.valuePoints;
   180→    const formattedPointsValue =
   181→      marketplaceValuePoints !== undefined && marketplaceValuePoints !== null
   182→        ? `- ${getFormattedPointsValueForMarketplace(marketplaceValuePoints)}`
   183→        : getFormattedPointsValue(
   184→            enrichedTransaction.amount,
   185→            enrichedTransaction.type,
   186→          );
   187→    const marketplaceTitle = getMarketplaceTitle(enrichedTransaction);
   188→    const cardTitle = marketplaceTitle || enrichedTransaction.description || '';
   189→    const highlightText = getFormattedHighlightText(
   190→      enrichedTransaction.date,
   191→      gainType,
   192→      moment,
   193→    );
   194→
   195→    const isMarketplace = !!enrichedTransaction?.marketplace;
   196→    const marketplace = enrichedTransaction?.marketplace;
   197→
   198→    let marketplaceContent: MarketplaceContentData | undefined;
   199→    if (isMarketplace && marketplace) {
   200→      const firstOrder = marketplace.orders?.[0];
   201→      const firstPayment = marketplace.payments?.[0];
   202→      const vendorName = firstOrder?.vendor || '';
   203→
   204→      const items: MarketplaceItemData[] = [];
   205→      marketplace.orders?.forEach(order => {
   206→        order.items?.forEach(item => {
   207→          items.push({
   208→            name: item.name,
   209→            quantity: item.quantity,
   210→            valuePoints: getFormattedPointsValueForMarketplace(
   211→              item.valuePoints,
   212→            ),
   213→            imageUrl: item.imageUrl,
   214→            cleanedImageUrl: getCleanedImageUrl(item.imageUrl),
   215→          });
   216→        });
   217→      });
   218→
   219→      marketplaceContent = {
   220→        orderNumber: enrichedTransaction.id,
   221→        status: enrichedTransaction.status,
   222→        statusColor: enrichedTransaction.status
   223→          ? STATUS_COLORS[enrichedTransaction.status] || 'neutral'
   224→          : undefined,
   225→        paymentType: firstPayment
   226→          ? getPaymentTypeLabel(firstPayment.paymentType)
   227→          : undefined,
   228→        shippingValuePoints:
   229→          marketplace.shippingValuePoints !== undefined &&
   230→          marketplace.shippingValuePoints !== null
   231→            ? getFormattedPointsValueForMarketplace(
   232→                marketplace.shippingValuePoints,
   233→              )
   234→            : undefined,
   235→        valuePoints:
   236→          marketplace.valuePoints !== undefined &&
   237→          marketplace.valuePoints !== null
   238→            ? getFormattedPointsValueForMarketplace(marketplace.valuePoints)
   239→            : undefined,
   240→        vendorName: vendorName || undefined,
   241→        items,
   242→      };
   243→    }
   244→
   245→    return {
   246→      cardTitle,
   247→      formattedPointsValue,
   248→      highlightText,
   249→      formattedCurrencyValue,
   250→      marketplaceContent,
   251→      showOrderNumber: !isMarketplace,
   252→      showStatus: !isMarketplace,
   253→      showValue: !isMarketplace,
   254→    };
   255→  }, [enrichedTransaction]);
   256→
   257→  return (
   258→    <MyOrdersDetailView
   259→      handleGoBack={handleGoBack}
   260→      transaction={enrichedTransaction}
   261→      modalizeRef={modalizeRef}
   262→      modalizeRefInfo={modalizeRefInfo}
   263→      handleOpenReportProblem={handleOpenReportProblem}
   264→      handleCloseReportProblem={handleCloseReportProblem}
   265→      handleOpenInfo={handleOpenInfo}
   266→      handleCloseInfo={handleCloseInfo}
   267→      isLoading={isLoading}
   268→      hasError={hasError}
   269→      handleRetry={handleRetry}
   270→      isCashback={isCashback}
   271→      cardTitle={processedData.cardTitle}
   272→      formattedPointsValue={processedData.formattedPointsValue}
   273→      highlightText={processedData.highlightText}
   274→      formattedCurrencyValue={processedData.formattedCurrencyValue}
   275→      marketplaceContent={processedData.marketplaceContent}
   276→      showOrderNumber={processedData.showOrderNumber}
   277→      showStatus={processedData.showStatus}
   278→      showValue={processedData.showValue}
   279→      height={height}
   280→    />
   281→  );
   282→};
   283→
   284→export default MyOrdersDetails;
   285→

